CREATE TABLE J09D_temp AS
SELECT * FROM decision_talbe
WHERE TOUR LIKE 'J09D%';

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'KSA'
WHERE HAUS IN (
  SELECT HAUS FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
    FROM J09D_temp
    GROUP BY HAUS
  ) sub
  WHERE eq_count < 3
);

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HAUS IN (
  SELECT HAUS FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
    FROM J09D_temp
    GROUP BY HAUS
  ) sub
  WHERE eq_count >= 3
);

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

UPDATE J09D_enriched
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (SELECT EQUNR FROM J09D_mandatory_eq);

